import{_ as i,c as o,o as r,j as e,ae as d,a as n,t as a}from"./chunks/framework.CLNW5JS9.js";const b=JSON.parse('{"title":"uni-app 上传到 TestFlight","description":"使用 HBuilderX 云打包构建 ipa 包并上传到 TestFlight","frontmatter":{"title":"uni-app 上传到 TestFlight","lang":"zh-CN","description":"使用 HBuilderX 云打包构建 ipa 包并上传到 TestFlight"},"headers":[],"relativePath":"zh-CN/38-build-uni-app-upload-to-testflight.md","filePath":"zh-CN/38-build-uni-app-upload-to-testflight.md"}'),s={name:"zh-CN/38-build-uni-app-upload-to-testflight.md"},p={id:"frontmatter-title",tabindex:"-1"};function h(l,t,g,c,f,x){return r(),o("div",null,[e("h1",p,[n(a(l.$frontmatter.title)+" ",1),t[0]||(t[0]=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1))]),e("p",null,a(l.$frontmatter.description),1),t[1]||(t[1]=d('<h2 id="应用图标" tabindex="-1">应用图标 <a class="header-anchor" href="#应用图标" aria-label="Permalink to &quot;应用图标&quot;">​</a></h2><p>注意：打包前必须在 <code>manifest.json</code> 中配置 App 图标（1024x1024），否则上传 TestFlight 时会报错。</p><h2 id="更新版本号" tabindex="-1">更新版本号 <a class="header-anchor" href="#更新版本号" aria-label="Permalink to &quot;更新版本号&quot;">​</a></h2><p>打包前必须更新版本号，否则上传 TestFlight 时会报错。</p><ul><li><strong>版本名称 (versionName)</strong>：用户可见的版本号，如 <code>1.0.1</code>。需<strong>大于应用商店当前上架的版本</strong>。在同个版本的多次测试提交中可以保持不变。</li><li><strong>版本号 (versionCode)</strong>：内部递增的整数。每次**提交（上传）**到 TestFlight 的包，其 <code>versionCode</code> <strong>必须</strong>比上一个递增（如从 1 改为 2）。即使版本名称没变，或者之前的包上传失败了，也需要增加。</li></ul><h2 id="证书与描述文件" tabindex="-1">证书与描述文件 <a class="header-anchor" href="#证书与描述文件" aria-label="Permalink to &quot;证书与描述文件&quot;">​</a></h2><p>证书与描述文件获取方法</p><blockquote><p><a href="https://ask.dcloud.net.cn/article/152" target="_blank" rel="noreferrer">iOS证书(.p12)和描述文件(.mobileprovision)申请 | DCloud</a></p></blockquote><p>证书与描述文件作用</p><table tabindex="0"><thead><tr><th style="text-align:left;">文件类型</th><th style="text-align:left;">扩展名</th><th style="text-align:left;">作用</th></tr></thead><tbody><tr><td style="text-align:left;">公钥</td><td style="text-align:left;"><code>.cer</code></td><td style="text-align:left;">证明&quot;我是谁&quot;, 配合私钥可以给 App 签名</td></tr><tr><td style="text-align:left;">私钥证书</td><td style="text-align:left;"><code>.p12</code></td><td style="text-align:left;">公钥 + 私钥, 用来给 App 签名, 通常有密码保护. 一旦泄露, 别人可以用你的身份签 App.</td></tr><tr><td style="text-align:left;">描述文件</td><td style="text-align:left;"><code>.mobileprovision</code></td><td style="text-align:left;">不能给 App 签名, 只是记录了这个 App 是谁签的，用了哪些能力，可以装到哪些设备上</td></tr></tbody></table><p>证书类型选择</p><table tabindex="0"><thead><tr><th style="text-align:left;">证书类型</th><th style="text-align:left;">使用场景</th><th style="text-align:left;">能否装真机</th><th style="text-align:left;">能否上 TestFlight</th></tr></thead><tbody><tr><td style="text-align:left;">iOS App Development</td><td style="text-align:left;">开发调试</td><td style="text-align:left;">✅ (需注册设备)</td><td style="text-align:left;">❌</td></tr><tr><td style="text-align:left;">Apple Distribution</td><td style="text-align:left;">提交 App Store</td><td style="text-align:left;">❌</td><td style="text-align:left;">✅</td></tr></tbody></table><h2 id="生成-ipa-包-云打包" tabindex="-1">生成 ipa 包(云打包) <a class="header-anchor" href="#生成-ipa-包-云打包" aria-label="Permalink to &quot;生成 ipa 包(云打包)&quot;">​</a></h2><p>这是最便捷的构建方式，在 HBuilderX 中点击 <code>发行</code> &gt; <code>原生App-云打包</code>。</p><table tabindex="0"><thead><tr><th style="text-align:left;">HBuilderX 打包配置</th><th style="text-align:left;">证书文件信息</th></tr></thead><tbody><tr><td style="text-align:left;">私钥证书</td><td style="text-align:left;"><code>.p12</code> 文件</td></tr><tr><td style="text-align:left;">证书私钥密码</td><td style="text-align:left;"><code>.p12</code> 文件的密码</td></tr><tr><td style="text-align:left;">证书 profile 文件</td><td style="text-align:left;"><code>.mobileprovision</code> 文件</td></tr></tbody></table><h2 id="上传-ipa-包" tabindex="-1">上传 ipa 包 <a class="header-anchor" href="#上传-ipa-包" aria-label="Permalink to &quot;上传 ipa 包&quot;">​</a></h2><ol><li>安装工具：在 Mac App Store 下载 <strong>Transporter</strong>。</li><li>登录：使用苹果开发者账号（App Store Connect 账号）登录。</li><li>交付：将生成的 Distribution 类型的 <code>.ipa</code> 包拖入 Transporter，点击“交付”。</li><li>观察：上传完成后，登录 <a href="https://appstoreconnect.apple.com/" target="_blank" rel="noreferrer">App Store Connect</a>，在“我的 App” &gt; 选择你的 App &gt; <strong>TestFlight</strong> 页面可以查看到上传的包。</li><li>处理：新包上传后状态为“正在处理”（Processing），通常需等待 10-30 分钟。处理完成后，你（作为开发人员）会收到一封通知邮件。</li></ol><h2 id="后续步骤-合规性与测试" tabindex="-1">后续步骤：合规性与测试 <a class="header-anchor" href="#后续步骤-合规性与测试" aria-label="Permalink to &quot;后续步骤：合规性与测试&quot;">​</a></h2><p>上传成功且处理完成后，在 App Store Connect 的“测试员”页面可能会看到“缺少合规信息”。</p><ol><li>点击“缺少合规信息”。</li><li>根据 App 实际情况回答是否使用了加密（通常选择“否”）。</li><li>完成后即可开始内部测试或邀请外部测试员。</li></ol>',20))])}const y=i(s,[["render",h]]);export{b as __pageData,y as default};
